SELECT DISTINCT ?pkg ?name WHERE {
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?name }
  FILTER(CONTAINS(STR(?name), "TMT") && !CONTAINS(STR(?name), "::"))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?name (COUNT(?child) as ?childCount) WHERE {
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?name }
  OPTIONAL { ?pkg vocab:Element_ownedElement ?child }
  FILTER(!CONTAINS(STR(?name), "::"))
}
GROUP BY ?pkg ?name
ORDER BY DESC(?childCount)
LIMIT 25

